#!/usr/bin/env node
/**
 * Autoload Guard Pre-Edit Hook
 *
 * Warns when trying to directly edit Composer autoload files.
 * These should be generated by `composer dump-autoload -o`, not hand-edited.
 *
 * Reads tool input from stdin (Claude Code PreToolUse format).
 * Outputs a warning message but does NOT block (exits 0).
 */

async function main() {
  let input = '';

  if (!process.stdin.isTTY) {
    input = await new Promise((resolve) => {
      const chunks = [];
      const timeout = setTimeout(() => resolve(chunks.join('')), 2000);
      process.stdin.on('data', (chunk) => chunks.push(chunk.toString()));
      process.stdin.on('end', () => { clearTimeout(timeout); resolve(chunks.join('')); });
      process.stdin.on('error', () => { clearTimeout(timeout); resolve(''); });
    });
  }

  let filePath = '';
  try {
    const data = JSON.parse(input);
    filePath = data.tool_input?.file_path || data.input?.file_path || '';
  } catch {
    process.exit(0);
  }

  if (!filePath) {
    process.exit(0);
  }

  // Normalize path separators
  const normalized = filePath.replace(/\\/g, '/').toLowerCase();

  if (normalized.includes('vendor/composer/autoload_classmap.php') ||
      normalized.includes('vendor/composer/autoload_static.php') ||
      normalized.includes('vendor/composer/autoload_psr4.php')) {
    process.stderr.write(
      `[Autoload Guard] WARNING: Editing ${filePath} directly.\n` +
      `These files should be generated by: composer dump-autoload -o\n` +
      `Consider using /dump-autoload instead.\n`
    );
  }
}

main().catch(() => {}).finally(() => process.exit(0));
